generated_oml:
// Sensing Component
instance JointTorqueSensor : DTDFVocab:SensingComponent [
    base:desc "Dynamic sensor measuring joint torque of the robot joint, transmitting data via CAN bus at 1 kHz."
    DTDFVocab:producedData JointTorqueDataTransmitted
]

// Data Transmitted
instance JointTorqueDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom JointTorqueSensor
]

// Data
instance JointTorqueData : DTDFVocab:Data [
    base:desc "Raw joint torque measurements stored for analysis."
    DTDFVocab:fromData JointTorqueDataTransmitted
    DTDFVocab:inputTo MontiArcAutomatonEnabler, SimulinkEngineEnabler, DigitalTwinModel
]

// Enabler – MontiArc Automaton
instance MontiArcAutomatonEnabler : DTDFVocab:Enabler [
    base:desc "Encapsulates MontiArc Automaton behavior, providing state‑transition logic for the digital twin."
    DTDFVocab:enables DecisionEngineService
]

// Enabler – Simulink Engine
instance SimulinkEngineEnabler : DTDFVocab:Enabler [
    base:desc "Runs MathWorks Simulink simulation to model continuous dynamics of the robot joint."
    DTDFVocab:enables DecisionEngineService
]

// Model – Digital Twin
instance DigitalTwinModel : DTDFVocab:Model [
    base:desc "Progressively enriched digital twin model capturing contextual data traces, augmented with MontiArc Automaton for discrete behavior and Simulink for continuous dynamics."
    DTDFVocab:inputTo MontiArcAutomatonEnabler, SimulinkEngineEnabler
]

// Service – Decision Engine
instance DecisionEngineService : DTDFVocab:Service [
    base:desc "Applies rule‑based engine with domain knowledge and probabilistic inference to balance system performance and maintenance costs."
    DTDFVocab:provides InsightJointFriction, ActionAdjustmentRecommendation
]

// Insight – Joint Friction Detection
instance InsightJointFriction : DTDFVocab:Insight [
    base:desc "Identifies friction in the robot joint by detecting systematic deviations between measured joint torques and simulated nominal behavior, quantifying residuals and confidence intervals."
]

// Action – Adjustment Recommendation
instance ActionAdjustmentRecommendation : DTDFVocab:Action [
    base:desc "Recommends adjustment of joint controller gains or replacement of worn bearings, with confidence level of 92%."
    DTDFVocab:IsAutomatic false
]

// Environment containing the sensor
instance RobotJointEnvironment : DTDFVocab:Environment [
    base:contains JointTorqueSensor
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The Digital Twin system is described using Model‑Based Systems Engineering (MBSE) techniques, leveraging SysML for system architecture and behavioral modeling, and architecture description languages such as ACME, AADL, MontiArc and SysML IBDs for component‑connector representations. These models are integrated with simulation environments (e.g., MathWorks Simulink) and code generation to C++ or Java, thereby providing an orchestrated architecture that coordinates component interactions, manages resources, and controls system‑wide behavior through a hierarchical decomposition of functional, logical and product/technical layers."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The development of a Digital Twin is described as proceeding through successive abstraction levels: requirements, functional architecture, logical architecture, and product/technical layers. Transitions between these stages are managed by model‑based systems engineering (MBSE) methods such as RFLP, OOSEM, SPES, or SMArDT, with consistency ensured by the use of architecture description languages (ADLs) and detailed behaviour models."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Standardisation is exemplified by the adoption of widely recognized modelling languages and architecture description languages. The document cites SysML (ISO/IEC‑standardised for system modelling), ACME, AADL, MontiArc, and SysML IBDs, as well as state‑machine models in SysML v1.7, indicating adherence to established industry standards for system description and behavioural modelling."
]
